# @cctt_verify {"v":2,"sym":"sympy.core.logic.fuzzy_xor","kind":"function","src_hash":"1ff928a4d5ffd6e6","in":{"base":"Any"},"out":{"base":"Any"},"spec":{"lhs":"fuzzy_xor(arg)","rhs":"return none if any element of args is not true or false, else true (if there are an odd number of true elements), else false","over":{"base":"Any"},"name":"fuzzy_xor_correct"},"guarantee":"return none if any element of args is not true or false, else true (if there are an odd number of true elements), else false","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.core.logic.fuzzy_xor_correct","statement":"Path(fuzzy_xor(x), return none if any element of args is not true or false, else true (if there are an odd number of true elements), else false)"},"assumes":[],"trust":"LIBRARY","compiled":true,"vhash":"e20ec66195e85c4d"}
def fuzzy_xor(args):
    """Return None if any element of args is not True or False, else
    True (if there are an odd number of True elements), else False."""
    t = 0
    for a in args:
        ai = fuzzy_bool(a)
        if ai:
            t += 1
        elif ai is None:
            return
    return t % 2 == 1


